External knowledge: 
- Average performance and trend values are used to evaluate sector performance over time; 
- Average correlation and confidence levels indicate the strength and reliability of the relationships between sectors; 
- Visualization data provides a graphical representation of sector correlations and trends.

sql:
SELECT sector_id, AVG(performance_value) AS average_performance
FROM sector_performance
GROUP BY sector_id;

SELECT news_title
FROM sector_news
WHERE sector_id = 1;

SELECT COUNT(*) AS news_count
FROM sector_news
WHERE sector_id = 1;

SELECT sector_name
FROM sectors
WHERE sector_id = (SELECT sector_id FROM access_logs WHERE access_id = 1);

SELECT category, COUNT(*) AS sector_count
FROM sectors
GROUP BY category;
